import{_ as s,c as t,a as d,o as n}from"./app-CEcM0piI.js";const e={};function i(p,a){return n(),t("div",null,a[0]||(a[0]=[d(`<ul><li>零地址指令![[Clip_2024-06-05_09-32-01.png]] 不需要操作数，如空操作、停机、关中断等指令 堆栈计算机，两个操作数隐含存放在栈顶和次栈顶，计算结果压回栈顶</li><li>一地址指令![[Clip_2024-06-05_09-32-18.png]] 1.只需要单操作数，如加1、减1、取反、求补等指令含义：OP(A1)→A1，完成一条指令需要3次访存：取指→读A1→写A1 2.需要两个操作数，但其中一个操作数隐含在某个寄存器（如隐含在ACC)指令含义：(ACC)OP(A1)-ACC完成一条指令需要2次访存：取指→读A1</li><li>二地址指令![[Clip_2024-06-05_09-33-37 1.png]] 常用于需要两个操作数的算术运算、逻辑运算相关指令 指令含义：(A1)OP(A2)→A1 完成一条指令需要访存4次，取指→读A1→读A2→写A1</li><li>三地址指令![[Clip_2024-06-05_09-33-58.png]] 常用于需要两个操作数的算术运算、逻辑运算相关指令 指令含义：(A1)OP(A2)→A3</li><li>四地址指令![[Clip_2024-06-05_09-35-48.png]] 指令含义：(A1)OP(A2)→A3，A4=下一条将要执行指令的地址 完成一条指令需要访存4次，取指→读A1→读A2→写A3</li></ul><p>正常情况下：取指令之后PC+1，指向下一条指令 四地址指令：执行指令后，将PC的值修改位A4所指地址</p><p>指令字长：一条指令的总长度 (可能会变) 机器字长：CPU进行一次整数运算所能处理的二进制数据的位数（通常和ALU直接相关) 存储字长：个存储单元中的二进制代码位数（通常和MDR位数相同）</p><ul><li><p>按指令长度分类 定长指令字结构：指令系统中所有指令的长度都相等 变长指令字结构：指令系统中各种指令的长度不等</p></li><li><p>按操作码长度分类 定长操作码：指令系统中所有指令的操作码长度都相同 可变长操作码：指令系统中各指令的操作码长度可变</p></li></ul><p>扩展操作码指令格式 定长指令字结构+可变长操作码</p><h1 id="指令寻址" tabindex="-1"><a class="header-anchor" href="#指令寻址"><span>指令寻址</span></a></h1><h2 id="顺序寻址" tabindex="-1"><a class="header-anchor" href="#顺序寻址"><span>顺序寻址</span></a></h2><p>若是定长的指令则程序执行的时候程序计数器pc只需要加上固定的指令字长就可以了 如果是边长的指令，程序执行的时候会根据其前面的操作码确定这个指令的长度是多少按照相应的指令给pc加上正确的值来取正确的指令</p><h2 id="跳跃寻址" tabindex="-1"><a class="header-anchor" href="#跳跃寻址"><span>跳跃寻址</span></a></h2><p>根据转移类的指令来确定下一个要运行的指令的地址</p><h1 id="数据寻址" tabindex="-1"><a class="header-anchor" href="#数据寻址"><span>数据寻址</span></a></h1><p>确定本指令的地址码指向的真实地址 ![[Clip_2024-06-05_20-54-44.png]] 第一种情况7代表的是数据的地址 第二种情况7代表着相对于程序入口的偏移量 第三个情况3代表着基于程序计数器pc向后偏移的位置 要区分数据寻址的方式需要在操作码和形式地址中间插入一个4bit 的寻址特征 ![[Clip_2024-06-05_21-00-22.png]] 对于而地址指令有两个地址因此需要给两个形式地址各设置一个寻址特征</p><table><thead><tr><th>寻址方式</th><th>特征码</th></tr></thead><tbody><tr><td>隐含寻址</td><td>0000</td></tr><tr><td>立即寻址</td><td>0001</td></tr><tr><td>直接寻址</td><td>0010</td></tr><tr><td>间接寻址</td><td>0011</td></tr><tr><td>寄存器寻址</td><td>0100</td></tr><tr><td>寄存器间接寻址</td><td>0101</td></tr><tr><td>相对寻址</td><td>0110</td></tr><tr><td>基址寻址</td><td>0111</td></tr><tr><td>变址寻址</td><td>1000</td></tr><tr><td>堆栈寻址</td><td>1001</td></tr></tbody></table><h3 id="直接寻址" tabindex="-1"><a class="header-anchor" href="#直接寻址"><span>直接寻址</span></a></h3><p>指令字中的地址就是操作数的真实地址 ![[Clip_2024-06-05_21-05-40.png]] 优点：简单，指令执行阶段仅访问一次主存不需专门计算操作数的地址 缺点：A的位数决定了该指令操作数的寻址范围操作数的地址不易修改</p><h3 id="间接寻址" tabindex="-1"><a class="header-anchor" href="#间接寻址"><span>间接寻址</span></a></h3><p>指令的地址字段给出的形式地址不是操作数的真止地址，而是操作数有效地址所在的存储单元的地址，也就是操作数地址的地址，即EA=(A)。 ![[Clip_2024-06-05_21-06-44.png]] 优点：可扩大寻址范围(有效地址EA的位数大于形式地址A的位数)。便于编制程序(用间接寻址可以方便地完成子程序返回)。</p><h3 id="寄存器寻址" tabindex="-1"><a class="header-anchor" href="#寄存器寻址"><span>寄存器寻址</span></a></h3><p>在指令字中直接给出操作数所在的寄存器编号，即EA=R，其操作数在由R;所指的寄存器内。 ![[Clip_2024-06-05_21-09-12.png]] 优点：指令在执行阶段不访问主存，只访问寄存器指令字短且执行速度快，支持向量/矩阵运算 缺点：寄存器价格昂贵，计算机中寄存器个数有限</p><h3 id="寄存器间接寻址" tabindex="-1"><a class="header-anchor" href="#寄存器间接寻址"><span>寄存器间接寻址</span></a></h3><p>寄存器R;中给出的不是一个操作数，而是操作数所在主存单元的地址，即EA=(R;)。 ![[Clip_2024-06-05_21-10-08.png]] 特点：与一般间接寻址相比速度更快但指令的执行阶段需要访问主存(因为操作数在主存中)。</p><h3 id="隐含寻址" tabindex="-1"><a class="header-anchor" href="#隐含寻址"><span>隐含寻址</span></a></h3><p>不是明显地给出操作数的地址，而是在指令中隐含着操作数的地址。 ![[Clip_2024-06-05_21-10-55.png]] 优点：有利于缩短指令字长 缺点：需增加存储操作数或隐含地址的硬件</p><h3 id="立即寻址" tabindex="-1"><a class="header-anchor" href="#立即寻址"><span>立即寻址</span></a></h3><p>形式地址A就是操作数本身，又称为立即数，一般采用补码形式。#表示立即寻址特征。</p><p>优点：指令执行阶段不访问主存，指令执行时间最短 缺点：A的位数限制了立即数的范围。如A的位数为n，且立即数采用补码时，可表示的数据范围为-2n-1～2n-1－1</p><h2 id="偏移寻址" tabindex="-1"><a class="header-anchor" href="#偏移寻址"><span>偏移寻址</span></a></h2><p>基址寻址、变址寻址、相对寻址都是偏移寻址，区别在于偏移的起点不一样</p><h3 id="基址寻址" tabindex="-1"><a class="header-anchor" href="#基址寻址"><span>基址寻址</span></a></h3><p>以程序的起始存放地址作为起点 将CPU中基址寄存器(BR)的内容加上指令格式中的形式地址A而形成操作数的有效地址，即EA=(BR)+A ![[Clip_2024-06-05_21-18-45.png]] 重定位寄存器就是基址寄存器</p><p>有的计算机使用通用寄存器作为基址寄存器，这时就需要在指令中指明要将哪个寄存器作为基址寄存器 ![[Clip_2024-06-05_21-21-16.png]] 优点：便于程序浮动，方便实现多道程序并发运行</p><p>注：基址寄存器是面向操作系统的，<mark>其内容由操作系统或管理程序确定</mark>。在程序执行过程中，基址寄存器的内容不变（作为基地址），形式地址可变（作为偏移量）。 当采用通用寄存器作为基址寄存器时，可由用户决定哪个寄存器作为基址寄存器但其内容仍由操作系统确定</p><h3 id="变址寻址" tabindex="-1"><a class="header-anchor" href="#变址寻址"><span>变址寻址</span></a></h3><p>程序员自已决定从哪里作为起点（以变址寄存器IX存储的地址作为起点） 有效地址EA等于指令字中的形式地址A与变址寄存器X的内容相加之和，即EA=(IX)+A,其中Ix可为变址寄存器（专用），也可用通用寄存器作为变址寄存器。 ![[Clip_2024-06-05_21-29-31 1.png]] 注：变址寄存器是面向用户的，在程序执行过程中，<mark>变址寄存器的内容可由用户改变（Ix作为偏移量）</mark>，形式地址A不变（作为基地址）</p><h3 id="相对寻址" tabindex="-1"><a class="header-anchor" href="#相对寻址"><span>相对寻址</span></a></h3><p>以程序计数器PC所指地址作为起点 把程序计数器PC的内容加上指令格式中的形式地址A而形成操作数的有效地址,即EA=(PC)A,其中A是相对于PC所指地址的位移量，可正可负，补码表示。 ![[Clip_2024-06-05_21-40-38.png]]</p><h3 id="堆栈寻址" tabindex="-1"><a class="header-anchor" href="#堆栈寻址"><span>堆栈寻址</span></a></h3><p>操作数存放在堆栈中，隐含使用堆栈指针(SP)作为操作数地址</p><h1 id="x86汇编" tabindex="-1"><a class="header-anchor" href="#x86汇编"><span>X86汇编</span></a></h1><h1 id="常用指令" tabindex="-1"><a class="header-anchor" href="#常用指令"><span>常用指令</span></a></h1><p>mov</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#mov指令功能：将源操作数s复制到目的操作数d所指的位置</span></span>
<span class="line"><span>mov 目的操作数d,源操作数s</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#将寄存器ebx的值复制到寄存器 eax</span></span>
<span class="line"><span>mov eax,ebx</span></span>
<span class="line"><span>#将立即数5复制到寄存器 eax</span></span>
<span class="line"><span>mov eax,5</span></span>
<span class="line"><span>#将内存地址af996h所指的32bit值复制到寄存器 eax</span></span>
<span class="line"><span>mov eax,dword ptr [af996h]</span></span>
<span class="line"><span>#将立即数5 复制到内存地址 af996h 所指的一字节中</span></span>
<span class="line"><span>mov byte ptr [af996h],5</span></span>
<span class="line"><span>#将 ebx 所指主存地址的 32bit 复制到 eax 寄存器中</span></span>
<span class="line"><span>mov eax, dword ptr [ebx]</span></span>
<span class="line"><span>#将 ebx+8 所指主存地址的 32bit 复制到eax 寄存器中（偏移8位）</span></span>
<span class="line"><span>mov eax, dword ptr [ebx+8]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>指明读写的长度 dword ptr 双字，32bit word ptr 单字，16bit byte ptr 字节，8bit 若没有指明读取的数据长度默认是32bit</p><p>[] 表示取地址</p><p>汇编中的地址都是十六进制</p><p>x86架构的CPU中的寄存器</p><p>通用寄存器可以存任意数据 X是未知表示不知道寄存器中存储的是什么数据</p><p>变址寄存器通常用于线性表和字符串的处理 堆栈寄存器用于函数实现 ![[Clip_2024-06-05_22-45-36.png]]</p><p>对于通用寄存器如果指令中不带e，如：mov ax,bx 此时代表只使用该寄存器的低16比特 且通用寄存器还可以使用更灵活直接使用低8bit，语法： mov ah，bl ah表示eax寄存器低16bit的前8bit，bl表示ebx寄存器低16bit的后8bit</p><p>而变址寄存器和堆栈寄存器只能固定使用32比特</p><p>指令对数据的操作有三种情况，一种是数据在寄存器中，这时指定寄存器即可，一种是数据在主存中需要指明其主存的逻辑地址，还有一种是直接数据可直接写在指令中</p><p>destination：目的地（d目的操作数）。source：来源地（s源操作数）</p><h3 id="算数运算指令" tabindex="-1"><a class="header-anchor" href="#算数运算指令"><span>算数运算指令</span></a></h3><table><thead><tr><th>指令</th><th>作用</th></tr></thead><tbody><tr><td>add d,s</td><td>计算d+s，结果存入d</td></tr><tr><td>sub d,s</td><td>计算d-s，结果存入d</td></tr><tr><td>mul d,s</td><td>无符号数d*s，乘积存入d</td></tr><tr><td>imul d,s</td><td>有符号数d*s，乘积存入d</td></tr><tr><td>div s</td><td>无符号数除法edx:eax/s，商存入eax，余数存入edx</td></tr><tr><td>idiv s</td><td>有符号数除法edx:eax/s，商存入eax，余数存入edx</td></tr><tr><td>neg d</td><td>将d取负数，结果存入d</td></tr><tr><td>inc d</td><td>将d++，结果存入d</td></tr><tr><td>dec d</td><td>将d--，结果存入d</td></tr><tr><td>对于将结果存入d的指令，不允许d是常量，只能是寄存器或内存</td><td></td></tr><tr><td>对于两个数的操作不允许两个操作数都来自主存，是为了不让每条指令访问太多次主存，访问太多次主存会影响运行速度</td><td></td></tr></tbody></table><h3 id="逻辑运算指令" tabindex="-1"><a class="header-anchor" href="#逻辑运算指令"><span>逻辑运算指令</span></a></h3><table><thead><tr><th>指令</th><th>操作</th></tr></thead><tbody><tr><td>and d,s</td><td>d和s逐位相与，结果放入d</td></tr><tr><td>or d,s</td><td>d和s逐位相或，结果放入d</td></tr><tr><td>not d</td><td>d逐位取反，结果放回d</td></tr><tr><td>xor d,s</td><td>d和s逐位异或，结果放入d</td></tr><tr><td>shl d,s</td><td>将d逻辑左移s位，结果放回d（通常s是常量）</td></tr><tr><td>shr d,s</td><td>将d逻辑右移s位，结果放回d（通常s是常量）</td></tr><tr><td>同样的d操作数不可以是常数</td><td></td></tr></tbody></table><p>用于实现分支结构、循环结构的指令：cmp、test、jmp、jxxx 用于实现函数调用的指令、push、pop、call、ret 用于实现数据转移的指令：mov</p><h3 id="at-t格式和intel格式" tabindex="-1"><a class="header-anchor" href="#at-t格式和intel格式"><span>AT&amp;T格式和Intel格式</span></a></h3><p>![[Clip_2024-06-06_10-05-22.png]]</p><p><strong>程序计数器pc（program counter）有时也被称为ip（instruction pointer）</strong></p><h3 id="实现分支循环的指令" tabindex="-1"><a class="header-anchor" href="#实现分支循环的指令"><span>实现分支循环的指令</span></a></h3><table><thead><tr><th>指令</th><th>作用</th></tr></thead><tbody><tr><td>jmp d</td><td>无条件跳转指令，指令无条件跳转到地址d</td></tr><tr><td>cmp a,b</td><td>比较a和b两个数</td></tr><tr><td>je d</td><td>jump when equal若a==b则跳转。ZF==1</td></tr><tr><td>jne d</td><td>jump when not equal若a!=b则跳转。ZF==0</td></tr><tr><td>jg d</td><td>jump when greater than若a&gt;b则跳转。ZF==0 &amp;&amp; SF==OF</td></tr><tr><td>jge d</td><td>jump when greater than若a&gt;=b则跳转。SF==OF</td></tr><tr><td>jl d</td><td>jump when less than若a&lt;b则跳转。SF!=OF</td></tr><tr><td>jle d</td><td>jump when less than or equal to若a&lt;=b则跳转。SF!=OF || ZF==1</td></tr><tr><td>jmp的地址可以以常量给出即目标地址，也可以取寄存器中的值，也可以取内存中的值</td><td></td></tr><tr><td>但直接给定值就很不灵活，如果程序改变跳转的地址就不是想要的地址了</td><td></td></tr><tr><td>可以使用锚点，锚点名可以任意取</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mov eax,7</span></span>
<span class="line"><span>mov ebx,6</span></span>
<span class="line"><span>jmp NEXT</span></span>
<span class="line"><span>mov ecx,edx</span></span>
<span class="line"><span>NEXT:</span></span>
<span class="line"><span>mov ecx,eax</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样即使程序的地址发生改变依旧可以跳转到需要的位置</p><p>cmp指令比较的底层原理是使两个操作数放到ALU中进行相减操作，得到四个标志位：</p><ol><li>OF（OverflowFlag）溢出标志。溢出时为1，否则置0</li><li>SF（SignFlag）符号标志。结果为负时置1，否则置0</li><li>ZF（ZeroFlag）零标志，运算结果为O时ZF位置1，否则置0</li><li>CF（CarryFlag）进位/借位标志，进位/借位时置1，否则置0 标志位存入PSW程序状态字寄存器（Intel称为标志寄存器），8086芯片中标志寄存器有16位 0位存CF标志位，6位存ZF标志位，7位存SF标志位，11位存OF标志位</li></ol><h3 id="函数调用" tabindex="-1"><a class="header-anchor" href="#函数调用"><span>函数调用</span></a></h3><table><thead><tr><th>指令</th><th>作用</th></tr></thead><tbody><tr><td>call 函数名</td><td>调用函数</td></tr><tr><td>ret</td><td>函数返回</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#定义函数add</span></span>
<span class="line"><span>add:</span></span>
<span class="line"><span>push ebp</span></span>
<span class="line"><span>mov ebp,esp</span></span>
<span class="line"><span>mov eax,[ebp+12]</span></span>
<span class="line"><span>mov edx,[ebp+8]</span></span>
<span class="line"><span>add eax,edx</span></span>
<span class="line"><span>leave</span></span>
<span class="line"><span>ret    #函数返回</span></span>
<span class="line"><span>call add    #调用add函数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>call指令的作用：</p><ol><li>将IP旧值压栈保存（保存在函数的栈帧顶部)</li><li>设置P新值无条件转移至被调用函数的第一条指令 ret指令的作用： 从函数的栈帧顶部找到IP旧值将其出栈并恢复IP寄存器</li></ol><h1 id="cisc和risc" tabindex="-1"><a class="header-anchor" href="#cisc和risc"><span>CISC和RISC</span></a></h1><h2 id="cisc" tabindex="-1"><a class="header-anchor" href="#cisc"><span>CISC</span></a></h2><p>complex instruction set computer复杂指令集的计算机系统 代表：x86架构，主要用于笔记本、台式机等 80-20规律：典型程序中的80%的语句仅仅使用处理机的20%的指令</p><h2 id="risc" tabindex="-1"><a class="header-anchor" href="#risc"><span>RISC</span></a></h2><p>reduced instruction set computer精简指令集的计算机系统 代表：arm架构，主要用于手机、平板等</p>`,76)]))}const l=s(e,[["render",i]]),h=JSON.parse('{"path":"/base/co/5/","title":"5、 指令格式","lang":"zh-CN","frontmatter":{"title":"5、 指令格式","createTime":"2025/06/18 20:43:30","permalink":"/base/co/5/"},"readingTime":{"minutes":11.99,"words":3598},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/计算机组成原理/5、指令格式.md","headers":[]}');export{l as comp,h as data};
